"""
MKT Christ Commentary — 1 Chronicles chapters 11–12
Run: python3 scripts/zc-christ-1chronicles-11-12.py

Ch11: All-Israel anointing of David at Hebron (11:1-3) — type of Christ's universal coronation;
      Jerusalem/Zion captured (11:4-9); David refuses the water-blood of his men (11:17-19)
Ch12: Spirit clothes Amasai (12:18); army growing like the army of God (12:22);
      all Israel with one heart makes David king (12:38-40)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "11": {
    "1": "<p>All Israel gathered to David at Hebron — &lsquo;Behold, we are your bone and flesh&rsquo; (v1). The universal gathering of Israel to anoint David as king after Saul&rsquo;s death is one of the OT&rsquo;s clearest types of the eschatological gathering of the nations to Christ. Eph 1:10 describes the cosmic plan of God &lsquo;to unite all things in him, things in heaven and things on earth&rsquo; — the Davidic kingship&rsquo;s all-Israel unification is the covenantal type of Christ&rsquo;s universal headship. The phrase &lsquo;your bone and flesh&rsquo; (<em>ʿaṣmᵉḵā ûḇᵉśārᵉḵā</em>) echoes Adam&rsquo;s recognition of Eve (&lsquo;bone of my bones and flesh of my flesh,&rsquo; Gen 2:23) — Paul applies the same bone-and-flesh language to the Church&rsquo;s union with Christ: &lsquo;we are members of his body&rsquo; (Eph 5:30).</p>",
    "2": "<p>YHWH had said: &lsquo;You shall be shepherd of my people Israel, and you shall be prince over my people Israel.&rsquo; David&rsquo;s kingship is explicitly framed as a shepherd-kingship from the beginning: YHWH&rsquo;s word to Samuel (cf. 2 Sam 5:2) defines the king&rsquo;s role as <em>rōʿeh</em> (shepherd) and <em>nāgîḏ</em> (leader/prince). Jesus takes up both titles: &lsquo;I am the good shepherd&rsquo; (John 10:11); &lsquo;Prince of Peace&rsquo; (Isa 9:6); &lsquo;the great Shepherd of the sheep&rsquo; (Heb 13:20). The Davidic coronation oracle is a shepherd-commissioning: the king is not a lord over Israel but a pastor for Israel — the pattern Christ fulfills as the one who lays down his life for the sheep (John 10:15).</p>",
    "3": "<p>David made a covenant with all the elders of Israel at Hebron before YHWH; they anointed him king. The threefold anointing of David (first privately by Samuel, 1 Sam 16; then king over Judah, 2 Sam 2:4; then king over all Israel here) parallels the structure of Christ&rsquo;s anointing/exaltation: the Spirit&rsquo;s descent at his baptism (the private anointing), his resurrection-exaltation (ruling in the new covenant community), and his return as universal King of kings (Rev 19:16). The covenant-making with elders &lsquo;before YHWH&rsquo; (&lsquo;in the presence of YHWH at Mizpah&rsquo; / &lsquo;before YHWH&rsquo;) establishes the covenant character of the kingship — it is not David&rsquo;s power but a covenant arrangement ratified by God.</p>",
    "4": "<p>David and all Israel went to Jerusalem (Jebus). The capture of Jerusalem follows immediately on the all-Israel anointing: the king&rsquo;s first act is to establish his city. The choice of Jebus/Jerusalem — a Canaanite city not in any tribal territory (on the border of Benjamin and Judah), with no prior Israelite association — is theologically significant: it is a new city for a new era of kingship. Rev 21:2 describes the &lsquo;holy city, new Jerusalem, coming down out of heaven from God&rsquo; — the eschatological Jerusalem is also a new city prepared for the greater king. The Chronicler links David&rsquo;s Jerusalem to the Messianic city from the moment of its capture.</p>",
    "5": "<p>The Jebusites said: &lsquo;You will not come in here.&rsquo; The seemingly impregnable Jebusite city rejected the coming king. The pattern is repeated in Christ&rsquo;s ministry: &lsquo;He came to his own, and his own people did not receive him&rsquo; (John 1:11). Jerusalem&rsquo;s rejection of David (the city&rsquo;s inhabitants say the lame and the blind could hold it, 2 Sam 5:6) prefigures Jerusalem&rsquo;s rejection of the greater David — the city that refused the Messiah was captured by him (not by military siege but by resurrection; Luke 24:49 instructs the disciples to stay in Jerusalem as the city where the Spirit would first be poured out).</p>",
    "6": "<p>Joab the son of Zeruiah went up first, and he became chief. The taking of Jerusalem required someone willing to lead the assault against the Jebusites. Joab&rsquo;s leadership of the city-taking charge makes him David&rsquo;s military commander. In the Christological type, the Church&rsquo;s advance into enemy-held territory requires those willing to go first into danger — the pattern of apostolic courage (Acts 4:29-31; Phil 1:20).</p>",
    "7": "<p>David dwelt in the stronghold; therefore they called it the city of David. The city receives its name from the king who takes it and inhabits it — &lsquo;the city of David.&rsquo; Ps 48:1-2 celebrates this: &lsquo;Great is YHWH and greatly to be praised in the city of our God, his holy mountain, beautiful in elevation, is the joy of all the earth, Mount Zion.&rsquo; Luke 2:11 announces Christ&rsquo;s birth &lsquo;in the city of David&rsquo; — the Messianic birthplace is named not after geographic coordinates but after the covenant king whose dynasty the newborn perpetuates.</p>",
    "8": "<p>David built the city all around, from the Millo in complete circuit; and Joab repaired the rest of the city. The king builds his city — an act of royal establishment that parallels the NT&rsquo;s description of Christ as the builder of a greater city. Heb 11:10 speaks of Abraham looking forward to &lsquo;the city that has foundations, whose designer and builder is God.&rsquo; Christ is both the King who inhabits the city and the builder who constructs it: &lsquo;I will build my church, and the gates of hell shall not prevail against it&rsquo; (Matt 16:18) — the Church is the building project of the one who captured the first city of David.</p>",
    "9": "<p>David became greater and greater, for YHWH of hosts was with him. The crescendo of the Jerusalem-capture section: the king&rsquo;s growing greatness is attributed entirely to YHWH&rsquo;s presence. Luke 2:40 uses the same crescendo language for Jesus: &lsquo;the child grew and became strong, filled with wisdom. And the favor of God was upon him.&rsquo; The pattern of progressive exaltation — each step of the Davidic/Messianic king&rsquo;s advancement is grounded in divine presence and favor — runs from David&rsquo;s Hebron anointing to Jesus&rsquo;s resurrection-exaltation (Phil 2:9: &lsquo;God has highly exalted him and bestowed on him the name that is above every name&rsquo;).</p>",
    "10": "<p>These are the chiefs of David&rsquo;s mighty men (<em>gibbōrîm</em>) who held strongly with him in his kingdom. The <em>gibbōrîm</em> (mighty ones) are the elite warrior community that formed around David before and after his coronation. They are types of the covenant community around the Messianic king: those who &lsquo;held strongly&rsquo; with him through the years of exile and persecution. Eph 6:10 calls believers to &lsquo;be strong in the Lord and in the strength of his might&rsquo; (<em>en tē dynamei tēs ischuos autou</em>) — a &lsquo;mighty one&rsquo; language applied to every Christian as a warrior in the service of the greater David.</p>",
    "11": "<p>Jashobeam, a Hachmonite, was chief of the thirty; he wielded his spear against 300 whom he killed at one time. The singular feat of killing 300 with one weapon establishes Jashobeam as the supreme mighty man. His deed is preserved in YHWH&rsquo;s record of those who served David faithfully. Rev 2:26-27 promises to the one who conquers a share in the authority Christ received from the Father — those who hold fast and overcome with their king receive a warrior&rsquo;s reward, just as David&rsquo;s mighty men are named and honored for their deeds on his behalf.</p>",
    "12": "<p>Eleazar son of Dodo the Ahohite — one of the three mighty men. The Three form the inner circle of David&rsquo;s warrior elite, distinguished for deeds of exceptional individual valor. The inner circle pattern recurs in the NT: Peter, James, and John form Christ&rsquo;s inner circle of three (Mark 9:2: the Transfiguration; Mark 14:33: Gethsemane). The pattern of an inner-circle-within-the-twelve within the broader community of followers is a consistent Messianic-community structure.</p>",
    "13": "<p>Eleazar was with David at Pas-dammim when the Philistines gathered there for battle. The place-name Pas-dammim means &lsquo;portion/boundary of bloodshed&rsquo; — the battle occurred at a site already named for blood. The mighty man&rsquo;s faithfulness at the place of bloodshed foreshadows the NT pattern where the Messianic community is called to stand firm at the place of danger. Rev 12:11: &lsquo;they have conquered him by the blood of the Lamb and by the word of their testimony, for they loved not their lives even unto death.&rsquo;</p>",
    "14": "<p>They took their stand in the middle of the plot and defended it, and struck down the Philistines. YHWH saved them by a great victory. The pattern: the mighty men held their ground in a field of barley; YHWH gave the victory. The deliverance comes from YHWH, but it comes through those who refuse to flee. The same pattern governs the Church&rsquo;s engagement with the powers: &lsquo;resist him, firm in your faith&rsquo; (1 Pet 5:9); &lsquo;having done all, to stand firm. Stand therefore&rsquo; (Eph 6:13-14).</p>",
    "15": "<p>Three of the thirty chiefs went down to the rock to David at the cave of Adullam, while the army of the Philistines was encamped in the Valley of Rephaim. The three mighty men went to find David in his outlaw cave period — before the kingship was established. Their loyalty preceded the throne: they served David in his time of weakness, not only in his triumph. Heb 13:13: &lsquo;let us go to him outside the camp and bear the reproach he endured&rsquo; — the call to join Christ in his rejected, pre-glory position before the throne is established.</p>",
    "16": "<p>David was then in the stronghold; and the garrison of the Philistines was then at Bethlehem. David yearned for water from Bethlehem (v17) while his enemies occupied his hometown. The exile period of the coming king — when his birthplace is enemy territory — is a type of the Incarnation&rsquo;s humiliation: the one who owns all came to his own and found enemy occupation (John 1:11). The Messianic king&rsquo;s homesickness for his rightful inheritance is a type of Christ&rsquo;s mission to reclaim what was lost.</p>",
    "17": "<p>David said: &lsquo;Oh that someone would give me water to drink from the well of Bethlehem that is by the gate!&rsquo; David&rsquo;s longing for Bethlehem&rsquo;s water — a yearning, not a command — moves three mighty men to risk their lives to bring it. The drinking-water/blood parallel is inescapable in the Christological reading: Christ longed for the salvation of the world; his followers went to the cross on his behalf; and he in turn poured himself out as a drink-offering (Phil 2:17; 2 Tim 4:6) for their sake. The direction of sacrifice reverses: David&rsquo;s men bled for water; Christ bled for others.</p>",
    "18": "<p>The three broke through the Philistine camp and drew water from the well of Bethlehem and brought it to David. But David would not drink it. He poured it out to YHWH and said: &lsquo;Far be it from me before my God that I should do this. Shall I drink the lifeblood of these men? For at the risk of their lives they brought it.&rsquo; David&rsquo;s refusal to drink the water his men risked death to obtain — and his pouring it out as a libation to YHWH — is one of the OT&rsquo;s most theologically rich acts of sacrificial renunciation. The water his men risked their blood to bring becomes blood in David&rsquo;s interpretation: to drink it would be to consume the risk they paid with their lives. So he gives it to YHWH. This prefigures Christ&rsquo;s own self-giving: the cup the Father gave him was a cup of sacrifice (Matt 26:39: &lsquo;let this cup pass from me; nevertheless, not as I will, but as you will&rsquo;). David poured out the water his servants&rsquo; blood-risk produced; Christ poured out his own blood on behalf of his servants. The drink-offering imagery (Num 28:7; Phil 2:17: &lsquo;I am being poured out as a drink offering upon the sacrificial offering of your faith&rsquo;) runs from this act through the Psalms into the NT&rsquo;s sacrificial theology.</p>",
    "19": "<p>So David would not drink it. The refusal is absolute and sacrificial: the king will not consume what his servants bled to provide. These things the three mighty men did. The preservation of these men&rsquo;s names and deeds in the chronicle is itself a type of the promise that those who serve Christ faithfully will be honored: &lsquo;If anyone serves me, the Father will honor him&rsquo; (John 12:26). The names of David&rsquo;s mighty men are written in YHWH&rsquo;s chronicle; the names of Christ&rsquo;s servants are written in the Lamb&rsquo;s book of life (Rev 21:27).</p>",
    "20": "<p>Abishai, the brother of Joab, was chief of the thirty. He lifted up his spear against 300 men and killed them and won a name beside the three. Abishai&rsquo;s feat (300 killed) mirrors Jashobeam&rsquo;s (v11), placing him at the honor-boundary of the three inner-circle mighty men. The &lsquo;name&rsquo; (<em>šēm</em>) he won by his deeds echoes the OT tradition of honorable memorial. Phil 4:3: &lsquo;whose names are in the book of life&rsquo; — the NT application of the honor-name tradition to eternal covenant membership.</p>",
    "21": "<p>He was the most renowned of the thirty and became their commander, but he did not attain to the three. The graduated honor system among David&rsquo;s warriors (The Three, then the Thirty, then the broader mighty men) reflects the covenant community&rsquo;s internal differentiation by faithfulness and deed. 1 Cor 15:41: &lsquo;star differs from star in glory&rsquo; — the NT similarly maintains degrees of honor in the resurrection community, proportional to faithfulness in service.</p>",
    "22": "<p>Benaiah the son of Jehoiada was a valiant man from Kabzeel, a doer of great deeds. He struck down two ariels of Moab. He also went down and struck down a lion in a pit on a day when snow had fallen. The lion-in-a-pit episode is the warrior type of Christ&rsquo;s descent to the place of death to defeat the enemy: Benaiah went down (<em>yāraḏ</em>) into the pit and killed the lion under the most adverse conditions (snow, confined space). Christ descended into death and defeated &lsquo;him who has the power of death, that is, the devil&rsquo; (Heb 2:14), the Lion&rsquo;s adversary, in the confined pit of the tomb. The warrior who goes into the pit and comes back victorious is a type of the resurrection.</p>",
    "23": "<p>Benaiah struck down an Egyptian man, a man of great stature, five cubits tall. The Egyptian held a spear like a weaver&rsquo;s beam, but Benaiah went down to him with a staff, snatched the spear, and killed him with his own spear. Benaiah defeated a giant Egyptian with the enemy&rsquo;s own weapon — the logic of the cross: Christ was &lsquo;put to death in the flesh&rsquo; (1 Pet 3:18), but through that very death disarmed the powers (&lsquo;through death he might destroy the one who has the power of death,&rsquo; Heb 2:14; Col 2:15: &lsquo;disarming the rulers and authorities and putting them to open shame, by triumphing over them in him&rsquo;). The enemy&rsquo;s weapon (death) became the instrument of the enemy&rsquo;s defeat.</p>",
    "24": "<p>Benaiah son of Jehoiada did these things and won a name beside the three mighty men. He was renowned among the thirty, but he did not attain to the three; and David set him over his bodyguard. Benaiah&rsquo;s role as commander of David&rsquo;s bodyguard (the Cherethites and Pelethites) established him as the king&rsquo;s personal protector. He later supported Solomon&rsquo;s succession (1 Kgs 1:38) and became Solomon&rsquo;s military commander (1 Kgs 2:35). His faithfulness across two reigns — David and Solomon — is a type of the faithful servant who serves the king and his son.</p>",
    "25": "<p>David set Benaiah over his bodyguard. The honor record continues. The pattern of faithful service receiving an elevated appointment — Benaiah served as a mighty man and was appointed to command — mirrors the parable of the talents: &lsquo;Well done, good and faithful servant. You have been faithful over a little; I will set you over much&rsquo; (Matt 25:21). Covenant faithfulness receives expanded covenant responsibility.</p>",
    "26": "<p>The mighty men of the armies: Asahel the brother of Joab, Elhanan the son of Dodo of Bethlehem — the Thirty begins. Asahel (killed by Abner, 2 Sam 2:18-23) was one of the three sons of Zeruiah (David&rsquo;s sister) — David&rsquo;s nephew. His name appears first in the Thirty, honoring a fallen warrior. The memorial of the dead within the living community&rsquo;s honor-list prefigures Heb 11&rsquo;s &lsquo;cloud of witnesses&rsquo; — those who died in faith are still part of the covenant community&rsquo;s cloud of witnesses surrounding present believers.</p>",
    "27": "<p>Shammoth the Harorite, Helez the Pelonite — the Thirty continues. These names represent the extension of David&rsquo;s warrior community beyond the Three and Abishai/Benaiah. The breadth of the honored community — each name individually preserved — reflects the NT promise that every covenant member is individually known: &lsquo;the Lord knows those who are his&rsquo; (2 Tim 2:19); &lsquo;I know my sheep by name&rsquo; (John 10:3).</p>",
    "28": "<p>Ira the son of Ikkesh the Tekoite, Abiezer of Anathoth. Anathoth is the Levitical city near Jerusalem later famous as the birthplace of the prophet Jeremiah (Jer 1:1). The inclusion of Anathoth in the mighty-men list connects the warrior community to the prophetic tradition — both serve the Davidic covenant from their respective callings.</p>",
    "29": "<p>Sibbecai the Hushathite, Ilai the Ahohite. The geographic and tribal variety of David&rsquo;s thirty reflects the pan-Israel character of his rule — his warrior community draws from across the tribal territories. The NT community similarly draws from all nations: &lsquo;You are a chosen race, a royal priesthood, a holy nation, a people for his own possession&rsquo; (1 Pet 2:9), gathered from Jew and Gentile.</p>",
    "30": "<p>Maharai of Netophah, Heled the son of Baanah the Netophathite. Netophah is a village near Bethlehem, in the Judean heartland. Several of David&rsquo;s mighty men are from the immediate Bethlehem/Judah area — the concentration of loyal warriors in the Messianic birthplace region is a geographic type of the centrality of the covenant community around Christ&rsquo;s place of origin.</p>",
    "31": "<p>Ithai the son of Ribai of Gibeah of the Benjaminites, Benaiah of Pirathon. Gibeah of Benjamin was Saul&rsquo;s hometown (1 Sam 10:26) — and yet a Benjaminite from Gibeah is among David&rsquo;s mighty men. The inclusion of a warrior from the rival king&rsquo;s hometown in David&rsquo;s honor-community shows that the Messianic king&rsquo;s community transcends prior tribal loyalties. Paul&rsquo;s statement &lsquo;there is neither Jew nor Greek&rsquo; (Gal 3:28) carries the same boundary-crossing logic.</p>",
    "32": "<p>Hurai of the brooks of Gaash, Abiel the Arbathite. The brooks of Gaash are mentioned in Judg 2:9 as the location of Joshua&rsquo;s burial — a detail connecting David&rsquo;s warrior to the Joshua era. The Joshua-David typological connection (Joshua conquers the land, David consolidates it) underlies the NT&rsquo;s Jesus-typology (the name &lsquo;Joshua/Jesus&rsquo; means &lsquo;YHWH saves&rsquo;; Heb 4:8 notes that Joshua did not give the ultimate rest).</p>",
    "33": "<p>Azmaveth the Baharumite, Eliahba the Shaalbonite. Bahurim is mentioned in 2 Sam 16:5 as the place where Shimei cursed David during Absalom&rsquo;s revolt. A warrior from the very town of David&rsquo;s humiliation is among his honored mighty men — the king&rsquo;s community includes those from the places of his suffering.</p>",
    "34": "<p>The sons of Hashem the Gizonite, Jonathan the son of Shageh the Hararite. The Hararite warriors (hill-country warriors) appear in the list — David&rsquo;s mighty men drew from the highlands as well as the valleys. The geographic comprehensiveness of the list reflects the universal call of the Messianic king&rsquo;s community.</p>",
    "35": "<p>Ahiam the son of Sachar the Hararite, Eliphelet the son of Ur. Brief entry; the covenant honor-register continues. The names of David&rsquo;s faithful servants preserved across thirty centuries are a type of the permanent covenant memory: &lsquo;At that time those who feared the LORD spoke with one another. The LORD paid attention and heard them, and a book of remembrance was written before him of those who feared the LORD and esteemed his name&rsquo; (Mal 3:16).</p>",
    "36": "<p>Hepher the Mecherathite, Ahijah the Pelonite. Brief entry; the Thirty continues. The full list ensures that no faithful servant is forgotten — each name is individually preserved in the covenant chronicle.</p>",
    "37": "<p>Hezro the Carmelite, Naarai the son of Ezbai. Carmel in Judah is associated with Nabal and Abigail (1 Sam 25) — a warrior from the site of David&rsquo;s pre-kingship encounter with the covenant community&rsquo;s unfaithfulness (Nabal) and faithfulness (Abigail) is among his honored warriors.</p>",
    "38": "<p>Joel the brother of Nathan, Mibhar the son of Hagri. The Hagrite warriors (Transjordanian peoples related to the Ishmaelites) appear here — further evidence of the non-Israelite elements within David&rsquo;s warrior community. The international composition of David&rsquo;s mighty men anticipates the multinational composition of Christ&rsquo;s covenant community.</p>",
    "39": "<p>Zelek the Ammonite, Naharai the Berothite, the armor-bearer of Joab the son of Zeruiah. An Ammonite warrior — from Israel&rsquo;s traditional enemy — is among David&rsquo;s thirty mighty men. The Ammonites were under covenant prohibition (Deut 23:3-6), yet an Ammonite served David faithfully. This anticipates the radical boundary-crossing of the NT&rsquo;s Gentile inclusion, where even those &lsquo;excluded from the commonwealth of Israel&rsquo; (Eph 2:12) are brought near through Christ.</p>",
    "40": "<p>Ira the Ithrite, Gareb the Ithrite. The Ithrites were associated with Kiriath-jearim (2:53), the Ark&rsquo;s resting place before Jerusalem. Warriors from the city of the Ark serve the king who eventually brings the Ark to its permanent home — the covenant object and the covenant community converge in their service of the covenant king.</p>",
    "41": "<p>Uriah the Hittite, Zabad the son of Ahlai. Uriah the Hittite — named last among the Thirty, or close to last — is the soldier David had killed to cover his adultery with Bathsheba (2 Sam 11). His name in the honor-list is a permanent memorial of the covenant he kept while David broke it. Matthew names Bathsheba indirectly as &lsquo;the wife of Uriah&rsquo; (Matt 1:6) — Uriah&rsquo;s name is preserved in the Matthean genealogy as a permanent reminder that the Messianic line descended through the worst of David&rsquo;s sin. The inclusion of the wronged in the honor-register is a type of the final reversal: Rev 6:10 (&lsquo;how long before you will judge and avenge our blood on those who dwell on the earth?&rsquo;) — the wronged are remembered and vindicated.</p>",
    "42": "<p>Adina the son of Shiza the Reubenite, a leader of the Reubenites, and thirty with him. Reubenite warriors in David&rsquo;s service — the Transjordanian tribe serves the Jerusalem king. The comprehensive tribal integration of David&rsquo;s warrior community (Judahite, Benjaminite, Reubenite, Ammonite, Hittite) reflects the pan-tribal and even transnational character of the Messianic kingship.</p>",
    "43": "<p>Hanan the son of Maacah, and Joshaphat the Mithnite. The geographic range continues. David&rsquo;s mighty men came from across the Levant — their service is a type of the universal service that Christ&rsquo;s community renders: &lsquo;from every nation, from all tribes and peoples and languages&rsquo; (Rev 7:9) gathered in service of the Lamb.</p>",
    "44": "<p>Uzzia the Ashterathite, Shama and Jeiel the sons of Hotham the Aroerite. Aroer is a Transjordanian city (Deut 2:36); its warriors serve the western-Jordan king David. The integration of Transjordanian and Cisjordanian warriors under David&rsquo;s kingship anticipates the NT&rsquo;s integration of Israel and Gentiles under Christ&rsquo;s universal lordship (Eph 2:14-16: &lsquo;he himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility&rsquo;).</p>",
    "45": "<p>Jediael the son of Shimri, and Joha his brother, the Tizite. Brief entry; the warrior honor-register continues. The covenant community gathered around its king is preserved name by name — a pattern of individual recognition within collective service.</p>",
    "46": "<p>Eliel the Mahavite, and Jeribai and Joshaviah, the sons of Elnaam, and Ithmah the Moabite. A Moabite warrior among David&rsquo;s mighty men — connecting to Ruth the Moabitess who is in the Davidic genealogy (2:12). The Moabite thread runs from Ruth (David&rsquo;s great-grandmother) through to Ithmah the warrior: the people who were excluded from the assembly (Deut 23:3) are consistently woven into the covenant community&rsquo;s most honored roles.</p>",
    "47": "<p>Eliel, Obed, and Jaasiel the Mezobaite — the Thirty&rsquo;s honor-register closes. The list of thirty-seven names (including more than thirty in the final count) is the covenant community&rsquo;s hall of honor under the Davidic king. The Chronicler&rsquo;s preservation of their names across the centuries is the OT type of the promise: &lsquo;I will not blot his name out of the book of life. I will confess his name before my Father and before his angels&rsquo; (Rev 3:5). The names of the faithful are permanently inscribed in the covenant record.</p>"
  },
  "12": {
    "1": "<p>Those who came to David at Ziklag while he was still kept from the presence of Saul — the exile period of the king. Before the throne, before the coronation, before any recognition of David&rsquo;s legitimacy, these men came to him in his outlaw exile at Ziklag. Their pre-throne loyalty is the type of the NT call to follow Christ before his glory is publicly established: &lsquo;it does not yet appear what we shall be, but we know that when he appears we shall be like him&rsquo; (1 John 3:2). The community that gathers to the king before his exaltation shares in his exaltation.</p>",
    "2": "<p>Armed with bows, using both the right hand and the left to sling stones and to shoot arrows from the bow — these Benjaminite warriors could fight ambidextrously. The ability to fight from either side reflects the comprehensive readiness of the covenant warrior. Eph 6:10-18 describes the Christian&rsquo;s armor in terms that cover every angle of attack: front, back, sides. The ambidextrous warrior is a type of the comprehensive spiritual warrior who is not defenseless on any flank.</p>",
    "3": "<p>Ahiezer the chief and Joash, the sons of Shemaah of Gibeah — Benjaminites from Saul&rsquo;s hometown who defected to David. The defection of warriors from the enemy&rsquo;s hometown to the true king is theologically significant: even those from within the opposing kingdom recognized and joined the Messianic king before his public coronation. This mirrors the first disciples&rsquo; recognition of Jesus before his resurrection had established his kingship publicly.</p>",
    "4": "<p>Ishmaiah the Gibeonite, a mighty man among the thirty and over the thirty. The Gibeonites (associated with the tabernacle, the great high place; cf. 16:39) contribute a warrior to David&rsquo;s elite — those associated with the sanctuary serve the king. The pattern of priestly/sanctuary community and royal community overlapping in their service of the Davidic king anticipates the NT&rsquo;s &lsquo;royal priesthood&rsquo; (1 Pet 2:9) where the two roles are held together in the covenant community.</p>",
    "5": "<p>Jeremiah, Jahaziel, Johanan, Jozabad the Gederathite — more of those who came to David before his coronation. Brief entry; the pre-coronation community&rsquo;s covenant loyalty is the type of faith that precedes sight.</p>",
    "6": "<p>Eluzai, Jerimoth, Bealiah, Shemariah, Shephatiah the Haruphite. The Benjaminite warriors who came to David before his throne; brief entry. The names are preserved because their loyalty before the throne preceded the honor after the throne — a pattern the NT reverses: &lsquo;through many tribulations we must enter the kingdom of God&rsquo; (Acts 14:22); glory follows suffering.</p>",
    "7": "<p>Joelah and Zebadiah, the sons of Jeroham of Gedor. The Gedor warriors — from the southern Judean hills — add to the pre-coronation community around David. Brief entry; their faithful pre-throne service is preserved in the covenant record.</p>",
    "8": "<p>From the Gadites there separated themselves to David in the stronghold in the wilderness mighty men of valor, men trained for war, who could handle shield and spear, whose faces were like the faces of lions. Lions as the symbol of warrior courage — and the king they served was the Lion of Judah&rsquo;s tribe (Rev 5:5: &lsquo;the Lion of the tribe of Judah, the Root of David, has conquered&rsquo;). The Gadites crossed the Jordan in flood season (v15: &lsquo;when it had overflowed all its banks&rsquo;) to reach David — the covenant community that serves the Messianic king crosses dangerous waters to reach him.</p>",
    "9": "<p>Ezer was the chief, Obadiah second, Eliab third. The ranking of the Gadite warriors mirrors the ranking of the Thirty (and the Three) in ch 11 — graduated honor within the covenant community based on faithfulness and deeds.</p>",
    "10": "<p>Mishmannah fourth, Jeremiah fifth. The Gadite warrior list continues; brief entry. Each name is individually preserved in the covenant chronicle — a type of the individual knowledge Christ has of each member of his community: &lsquo;he calls his own sheep by name&rsquo; (John 10:3).</p>",
    "11": "<p>Attai sixth, Eliel seventh. Brief entry; the Gadite list continues. The sevenfold (or longer) structure of the Gadite warriors honors the group through the completeness of their named preservation.</p>",
    "12": "<p>Johanan eighth, Elzabad ninth. Brief entry; Gadite warriors in ranked order, each individually named and honored.</p>",
    "13": "<p>Jeremiah tenth, Machbannai eleventh. The Gadite warriors complete their eleven-member group. Brief entry; covenant honor preserved by name.</p>",
    "14": "<p>These Gadites were officers of the army, the lesser over a hundred and the greater over a thousand. The Gadites were not merely brave — they were experienced military commanders capable of organizing forces of 100 to 1,000. The covenant community around the Messianic king is not a disorganized mob but a structured community under capable leadership — the pattern that Paul applies to the church through his gifts-and-roles theology (Eph 4:11-13: apostles, prophets, evangelists, pastor-teachers).</p>",
    "15": "<p>These are the men who crossed the Jordan in the first month, when it was overflowing all its banks, and put to flight all those in the valleys, to the east and to the west. Crossing the Jordan in flood — the most dangerous time — to reach David is the type of radical covenant commitment that counts no obstacle too great. The Jordan-crossing imagery is loaded with Exodus/Joshua typology (Josh 3-4: Israel crossed the Jordan to enter the promised land). The Gadites crossed in the opposite direction (from east to west, from Transjordan into Judah) to reach the coming king — the covenant community crosses dangerous waters to come to the one who is &lsquo;greater than Joshua&rsquo; (Heb 4:8).</p>",
    "16": "<p>Some of the men of Benjamin and Judah came to the stronghold to David. Their arrival from the two tribes that shared the closest relationship to the Davidic kingship (Judah = David&rsquo;s tribe; Benjamin = Saul&rsquo;s tribe) shows that the pre-throne community was drawn from both those who might have been expected to support David and those who might have been expected to oppose him.</p>",
    "17": "<p>David went out to meet them and said: &lsquo;If you have come to me in peace, to help me, my heart will be knit to you; but if to betray me to my adversaries, although there is no wrong in my hands, then may the God of our fathers see and rebuke it.&rsquo; David&rsquo;s address to the ambiguous arrivals — is their heart toward him or against him? — is the type of Christ&rsquo;s call for unambiguous commitment: &lsquo;Whoever is not with me is against me, and whoever does not gather with me scatters&rsquo; (Matt 12:30). The covenant relationship with the Messianic king requires genuine heart-orientation, not performative loyalty.</p>",
    "18": "<p>Then the Spirit clothed itself with Amasai (<em>wᵉrûaḥ lāḇᵉšāh ʾet ʿămāśay</em>), chief of the thirty, and he said: &lsquo;We are yours, O David, and with you, O son of Jesse! Peace, peace to you, and peace to your helpers! For your God helps you.&rsquo; The language of the Spirit &lsquo;clothing itself&rsquo; with a person (<em>lāḇaš</em>, the same verb used for putting on clothing) is one of the OT&rsquo;s strongest Spirit-investiture formulas (also used for Gideon, Judg 6:34; and Zechariah son of Jehoiada, 2 Chr 24:20). Amasai&rsquo;s Spirit-inspired confession of loyalty to David anticipates the NT&rsquo;s pneumatological confession: &lsquo;No one can say &ldquo;Jesus is Lord&rdquo; except in the Holy Spirit&rsquo; (1 Cor 12:3). The Spirit-given declaration of the Davidic king&rsquo;s lordship (&lsquo;We are yours, O David&rsquo;) is the OT type of the Spirit-given declaration of the greater David&rsquo;s lordship.</p>",
    "19": "<p>Some of the men of Manasseh deserted to David when he came with the Philistines for the battle against Saul. The Manassites who defected to David at the most dangerous moment of his career — when he was about to fight his own king alongside the Philistines — demonstrate that even those from the northern tribes recognized David&rsquo;s legitimate kingship before he was able to exercise it publicly. The pre-coronation community continues to grow from unexpected sources.</p>",
    "20": "<p>When he went to Ziklag, these men of Manasseh deserted to him: Adnah, Jozabad, Jediael, Michael, Jozabad, Elihu, and Zillethai, chiefs of thousands in Manasseh. Tribal chiefs from Manasseh — men with authority over thousands — defected to the coming king. The pre-coronation community included not only individual warriors but established leaders. The early church similarly attracted established leaders: Nicodemus (John 3, 19), Joseph of Arimathea (Matt 27:57), Zacchaeus the tax-chief (Luke 19), and the many priests who &lsquo;became obedient to the faith&rsquo; (Acts 6:7).</p>",
    "21": "<p>They helped David against the band of raiders, for they were all mighty men of valor, and they were commanders in the army. The Manassites joined David in practical military service immediately upon arriving — they did not merely profess loyalty but demonstrated it in action. James 2:17: &lsquo;faith by itself, if it does not have works, is dead&rsquo; — the covenant community&rsquo;s loyalty is expressed in service, not merely declaration.</p>",
    "22": "<p>For from day to day men came to David to help him, until there was a great army, like an army of God (<em>kᵉmaḥăneh ʾĕlōhîm</em>). The crescendo of the pre-coronation gathering: the community around the coming king grew from a handful of mighty men to an army of God. The image of the &lsquo;army of God&rsquo; recalls the divine host (Gen 32:2: Jacob named the place Mahanaim (&lsquo;Two Camps&rsquo;) when he saw the angels). The pre-coronation Davidic army is assimilated to the divine host — a type of the NT church as the army of the living God (Eph 6:10-18; Rev 19:14: the armies of heaven following the Word of God).</p>",
    "23": "<p>These are the numbers of the divisions of the armed troops who came to David in Hebron, to turn the kingdom of Saul over to him, according to the word of YHWH. The census of those gathered to anoint David at Hebron — the &lsquo;according to the word of YHWH&rsquo; frames the gathering as prophetic fulfillment. The transfer of the kingdom from Saul to David is not a military coup but a divine appointment: the gathering at Hebron happens because YHWH decreed it. Acts 2:36: &lsquo;God has made him both Lord and Christ, this Jesus whom you crucified&rsquo; — Christ&rsquo;s coronation is equally a divine appointment, not a human political achievement.</p>",
    "24": "<p>The men of Judah bearing shield and spear — 6,800 armed troops. Judah&rsquo;s warriors lead the tribal muster list as the tribe of the Davidic king. The leading-tribe structure (Judah marches first, Num 10:14; Judah&rsquo;s lot falls first, Josh 15) consistently positions the Messianic tribe at the forefront of covenant community organization.</p>",
    "25": "<p>Of the Simeonites, mighty men of valor for war — 7,100. Simeon&rsquo;s warriors contribute to the Davidic coronation assembly. The full tribal muster — Judah, Simeon, Levi, Benjamin, Ephraim, Manasseh, Issachar, Zebulun, Naphtali, Dan, Asher, Reuben, Gad (vv24-37) — is the pan-Israel coronation that prefigures the eschatological gathering: Rev 7:4-8 lists all twelve tribes as sealed before the Lamb&rsquo;s enthronement.</p>",
    "26": "<p>Of the Levites — 4,600. The Levites contribute to the coronation muster — the priestly/cultic tribe participates in the installation of the covenant king. The integration of priestly and royal community at the coronation prefigures Christ&rsquo;s kingship that is simultaneously priestly (Heb 7:1-3; the Melchizedekian priest-king).</p>",
    "27": "<p>Jehoiada, the leader of the house of Aaron, and with him 3,700. The Aaronic priesthood sends its leader with warriors to the Davidic coronation — the high priestly community participates in the royal installation. The coordination of the Aaronic and Davidic institutions at the coronation prefigures the NT&rsquo;s coordination of Christ&rsquo;s priestly and royal offices in one person (Heb 5-7).</p>",
    "28": "<p>Zadok, a young man mighty in valor, and twenty-two commanders from his own father&rsquo;s house. Zadok&rsquo;s early appearance here (before his appointment as Aaronic high priest under David and Solomon) marks him as a young warrior at David&rsquo;s coronation who became the paradigm for priestly faithfulness. Ezek 44:15-16 honors the &lsquo;Levitical priests, the sons of Zadok&rsquo; as those who &lsquo;kept the charge of my sanctuary&rsquo; — Zadok&rsquo;s faithfulness at this coronation moment is the origin of his priestly dynasty&rsquo;s special honor.</p>",
    "29": "<p>Of the Benjaminites, the kinsmen of Saul — 3,000 (for until then the majority of them had kept their allegiance to the house of Saul). The Benjaminites are the smallest contributor to the coronation muster, and the Chronicler explains why: most Benjaminites were still loyal to Saul&rsquo;s house. Yet 3,000 crossed tribal and dynastic loyalty to anoint David. The pattern of defection from the old kingdom to the new recurs in the NT: Paul, a Benjaminite (Rom 11:1; Phil 3:5) &lsquo;from the tribe of Benjamin,&rsquo; crossed from Saul-like persecution to Davidic service — making him a living embodiment of this very verse&rsquo;s pattern.</p>",
    "30": "<p>Of the Ephraimites, 20,800, mighty men of valor, famous men in their fathers&rsquo; houses. Ephraim&rsquo;s large contribution (the dominant northern tribe) to the Davidic coronation at Hebron shows that the &lsquo;all Israel&rsquo; of v1 was genuinely comprehensive. The eschatological gathering of all Israel (including the northern tribes) around the Messianic king is the ultimate fulfillment: Ezek 37:15-28 (&lsquo;the two sticks&rsquo; united under one king, &lsquo;my servant David&rsquo;); Rev 7:4-8 (all twelve tribes sealed).</p>",
    "31": "<p>Of the half-tribe of Manasseh, 18,000, who were expressly named to come and make David king. The Manassites were not merely present but were &lsquo;expressly named&rsquo; — specifically designated to come for this purpose. The deliberate naming of individuals for the coronation-act is a type of election: those who come to anoint the Messianic king are not accidental bystanders but designated participants in the divine coronation decree.</p>",
    "32": "<p>Of Issachar, men who had understanding of the times, to know what Israel ought to do, 200 chiefs, and all their kinsmen under their command. The Issacharites are the wisdom-warriors: they bring not military numbers but discernment — &lsquo;understanding of the times&rsquo; (<em>yōdᵉʿê bînāh laʿittîm</em>). The NT calls for the same discernment: &lsquo;Look carefully then how you walk, not as unwise but as wise, making the best use of the time, because the days are evil&rsquo; (Eph 5:15-16). Wisdom about timing is a spiritual competency as necessary as military courage.</p>",
    "33": "<p>Of Zebulun, 50,000 seasoned troops, equipped for battle with all the weapons of war, to help David with singleness of purpose. &lsquo;Singleness of purpose&rsquo; (<em>lōʾ lēḇ wālēḇ</em>, literally &lsquo;not a heart and a heart&rsquo; — no double heart, undivided) is the covenant warrior&rsquo;s defining characteristic. Jas 4:8: &lsquo;Purify your hearts, you double-minded&rsquo; — the opposite of the Zebulunite singleness of heart. James calls for the undivided heart that Zebulun brought to David&rsquo;s coronation.</p>",
    "34": "<p>Of Naphtali, 1,000 commanders with whom were 37,000 men armed with shield and spear. Naphtali&rsquo;s northern territory (the region of the Sea of Galilee) would later be the location of Jesus&rsquo;s primary ministry — Matt 4:12-16 explicitly cites Isa 9:1-2 about &lsquo;the land of Zebulun and the land of Naphtali&rsquo; as fulfilled in Jesus&rsquo;s Galilean ministry. The Naphtali warriors who came to anoint David served in the region that centuries later recognized the greater David.</p>",
    "35": "<p>Of the Danites, 28,600 men equipped for battle. Dan&rsquo;s warriors join the all-Israel muster. Dan&rsquo;s territory at the northern extreme of the land (the expression &lsquo;from Dan to Beersheba&rsquo;) represents the geographic completeness of the coronation-gathering. The comprehensive geographic reach of the coronation assembly is a type of the universal mission: &lsquo;from the rising of the sun to its setting, my name will be great among the nations&rsquo; (Mal 1:11).</p>",
    "36": "<p>Of Asher, 40,000 seasoned troops ready for battle. Asher&rsquo;s territory (northwestern coast, including the area around Tyre and Sidon) borders the Gentile world — the edge-of-Israel tribe that touches the nations contributes to the coronation of the pan-Israel king. Anna the prophetess (Luke 2:36-38), who recognized the infant Jesus in the temple, was of the tribe of Asher — the northernmost tribe contributes early recognition of both Davids.</p>",
    "37": "<p>Of the Reubenites, the Gadites, and the half-tribe of Manasseh on the east side of the Jordan, 120,000 men armed with all sorts of weapons of war. The Transjordanian tribes — east of the Jordan, theoretically outside the core land — send the largest contingent: 120,000. Their massive contribution to the coronation muster shows that the covenant community&rsquo;s boundaries are not geographically defined. Those who seem peripheral (east of the Jordan, outside the heartland) bring the greatest number. The NT consistently reverses the center-periphery expectation: the Samaritans and Gentiles who seemed outside the covenant are often the most responsive (Luke 17:16: the one Samaritan leper who returned to give thanks; Acts 10: Cornelius).</p>",
    "38": "<p>All these, men of war, arrayed in battle order, came to Hebron with full intent to make David king over all Israel. And likewise all the rest of Israel were of a single mind to make David king. The all-Israel coronation at Hebron — &lsquo;a single mind&rsquo; (<em>lēḇ šālēm</em>, a complete/undivided heart) across every tribe — is the OT&rsquo;s fullest corporate image of covenant unity around the Davidic king. Phil 2:1-2: &lsquo;if there is... any participation in the Spirit... complete my joy by being of the same mind, having the same love, being in full accord and of one mind&rsquo; — Paul&rsquo;s call for ecclesial unity is modeled on this coronation-assembly pattern of a people with one undivided heart installing their king.</p>",
    "39": "<p>And they were there with David for three days, eating and drinking, for their brothers had made preparation for them. The three-day feast at Hebron consecrates the coronation community in shared table fellowship — &lsquo;brothers&rsquo; providing for the gathered assembly. The three-day structure (three days of feast following three days of travel to reach David) echoes the three-day resurrection pattern; the feast that follows David&rsquo;s installation as king is a type of the Messianic banquet: &lsquo;Blessed are those who are invited to the marriage supper of the Lamb&rsquo; (Rev 19:9).</p>",
    "40": "<p>And also their neighbors, from as far as Issachar and Zebulun and Naphtali, came bringing food on donkeys and on camels and on mules and on oxen — abundant provisions of flour, cakes of figs, clusters of raisins, wine, oil, oxen, and sheep, for there was joy in Israel. The coronation feast is an abundance — the overflow of provision from all the tribes, from near and far, brought as an act of covenant joy. &lsquo;There was joy in Israel&rsquo; (<em>kî śimḥāh bᵉyiśrāʾēl</em>) is the covenant community&rsquo;s unanimous response to the king&rsquo;s installation. Rev 19:7: &lsquo;Let us rejoice and exult and give him the glory, for the marriage of the Lamb has come.&rsquo; The joy of Hebron&rsquo;s coronation feast is a foretaste of the joy of the Lamb&rsquo;s ultimate coronation banquet.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', '1chronicles')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', '1chronicles', c)
    count = sum(len(v) for v in CHRIST.values())
    print(f'1chronicles mkt-christ: wrote {count} verses across ch 11-12')

if __name__ == '__main__':
    main()
